codeExample.before:
beforeEach(() => {
  originalRedisUrl = process.env.REDIS_URL;
  service = new MyService(); // May connect to Redis!
});

codeExample.after:
beforeEach(() => {
  originalRedisUrl = process.env.REDIS_URL;
  delete process.env.REDIS_URL; // Clear BEFORE instantiation
  service = new MyService(); // Won't connect to Redis
});

afterEach(() => {
  if (originalRedisUrl) process.env.REDIS_URL = originalRedisUrl;
  else delete process.env.REDIS_URL;
});

codeExample.code:
import { http, HttpResponse } from 'msw';
import { setupServer } from 'msw/node';

const server = setupServer(
  http.get('http://localhost:4000/api/users', () => {
    return HttpResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }),
  http.get('http://localhost:4000/admin/dashboard', () => {
    return HttpResponse.json({ error: 'Unauthorized' }, { status: 401 });
  })
);

beforeAll(() => server.listen({ onUnhandledRequest: 'warn' }));
afterEach(() => server.resetHandlers());
afterAll(() => server.close());

